def solve(nums, target):
    left, right = 0, len(nums) - 1
    while left < right:
        total = nums[left] + nums[right]
        if total == target:
            return left, right
        if total < target:
            left += 1
        else:
            right -= 1
    return -1, -1

# Additional checks for no-solution case and ensuring indices are not reused
def solve_with_checks(nums, target):
    if len(nums) < 2:
        return -1, -1
    return solve(nums, target)
